import{l as e,a as t,c as r,a6 as h}from"./chunks/framework.C0d1FTMf.js";const u=JSON.parse('{"title":"思维模型","description":"","frontmatter":{},"headers":[],"relativePath":"blog/collection/think_method.md","filePath":"blog/collection/think_method.md"}'),o={name:"blog/collection/think_method.md"};function i(l,a,d,n,c,s){return t(),r("div",null,[...a[0]||(a[0]=[h('<h1 id="思维模型" tabindex="-1">思维模型 <a class="header-anchor" href="#思维模型" aria-label="Permalink to &quot;思维模型&quot;">​</a></h1><h2 id="理解" tabindex="-1">理解 <a class="header-anchor" href="#理解" aria-label="Permalink to &quot;理解&quot;">​</a></h2><h3 id="○-黄金思维圈" tabindex="-1">○ 黄金思维圈 <a class="header-anchor" href="#○-黄金思维圈" aria-label="Permalink to &quot;○ 黄金思维圈&quot;">​</a></h3><p>帮助理解目标并行动，激发共同信念。</p><ul><li><code>why</code>：内圈，为什么做这个</li><li><code>how</code>: 中圈，怎么做，梳理方法、流程、策略、行动</li><li><code>what</code>：外圈，成果，提供给他人使用的产品</li></ul><h3 id="○-mece-原则" tabindex="-1">○ MECE 原则 <a class="header-anchor" href="#○-mece-原则" aria-label="Permalink to &quot;○ MECE 原则&quot;">​</a></h3><p>独立分类，穷尽思考。类似树结构、金字塔（结论先行、自上而下表达，自下而上思考）</p><p>如：分析原因时，分“内部因素”和“外部因素”，再进一步往下分类穷尽。</p><h3 id="○-5w2h" tabindex="-1">○ 5W2H <a class="header-anchor" href="#○-5w2h" aria-label="Permalink to &quot;○ 5W2H&quot;">​</a></h3><p>何事、何因、何人、何时、何地、如何做、多少成本</p><h3 id="○-5why" tabindex="-1">○ 5Why <a class="header-anchor" href="#○-5why" aria-label="Permalink to &quot;○ 5Why&quot;">​</a></h3><p>连续追问 5 个 why，来分析问题根因。如：“机器停了→超负荷→保险丝断→润滑不够→吸油泵磨损→没及时更换滤网”</p><h3 id="○-orid" tabindex="-1">○ ORID <a class="header-anchor" href="#○-orid" aria-label="Permalink to &quot;○ ORID&quot;">​</a></h3><p>根据“客观 -&gt; 感受 -&gt; 诠释/理解 -&gt; 决定”来回顾书、事件。</p><h2 id="决策" tabindex="-1">决策 <a class="header-anchor" href="#决策" aria-label="Permalink to &quot;决策&quot;">​</a></h2><h3 id="○-10-10-10-原则" tabindex="-1">○ 10/10/10 原则 <a class="header-anchor" href="#○-10-10-10-原则" aria-label="Permalink to &quot;○ 10/10/10 原则&quot;">​</a></h3><p>帮助做决策。</p><p>考虑每个方案在 10 分钟、10 个月和 10 年后的影响，评估方案的长期效益再做决定。</p><h3 id="○-艾森豪威尔矩阵-四象限" tabindex="-1">○ 艾森豪威尔矩阵（四象限） <a class="header-anchor" href="#○-艾森豪威尔矩阵-四象限" aria-label="Permalink to &quot;○ 艾森豪威尔矩阵（四象限）&quot;">​</a></h3><p>按紧急→重要两个维度切分。优先做“重要不紧急”的事（如规划、锻炼），紧急不重要的尽量授权，既紧急又重要的立刻去做，两者皆无的果断放弃。</p><h3 id="○-加权决策矩阵" tabindex="-1">○ 加权决策矩阵 <a class="header-anchor" href="#○-加权决策矩阵" aria-label="Permalink to &quot;○ 加权决策矩阵&quot;">​</a></h3><p>先列出评分维度（如成本、效果、风险），按权重打分。</p><h3 id="○-六顶思考帽" tabindex="-1">○ 六顶思考帽 <a class="header-anchor" href="#○-六顶思考帽" aria-label="Permalink to &quot;○ 六顶思考帽&quot;">​</a></h3><p>避免开会时吵成一锅粥。白帽（客观事实）、红帽（直觉情绪）、黑帽（风险弱点）、黄帽（价值优点）、绿帽（创意替代）、蓝帽（掌控流程）</p><h3 id="○-第一性原理" tabindex="-1">○ 第一性原理 <a class="header-anchor" href="#○-第一性原理" aria-label="Permalink to &quot;○ 第一性原理&quot;">​</a></h3><p>不参考行业的通用做法，而是从原理出发设计最短步骤。</p><h3 id="○-pdca" tabindex="-1">○ PDCA <a class="header-anchor" href="#○-pdca" aria-label="Permalink to &quot;○ PDCA&quot;">​</a></h3><p>根据“计划 -&gt; 执行 -&gt; 检查 -&gt; 处理”，修复失败的流程，复用成功的流程。</p><h3 id="○-kiss" tabindex="-1">○ KISS <a class="header-anchor" href="#○-kiss" aria-label="Permalink to &quot;○ KISS&quot;">​</a></h3><p>根据“保留 -&gt; 改进 -&gt; 可尝试 -&gt; 需停止”来复盘</p><h3 id="○-逆向思维" tabindex="-1">○ 逆向思维 <a class="header-anchor" href="#○-逆向思维" aria-label="Permalink to &quot;○ 逆向思维&quot;">​</a></h3><p>从失败/终点倒退，识别风险，提前规避。</p><h2 id="说服" tabindex="-1">说服 <a class="header-anchor" href="#说服" aria-label="Permalink to &quot;说服&quot;">​</a></h2><h3 id="○-归纳" tabindex="-1">○ 归纳 <a class="header-anchor" href="#○-归纳" aria-label="Permalink to &quot;○ 归纳&quot;">​</a></h3><p>从一堆事实中提炼规律</p><h3 id="○-演绎" tabindex="-1">○ 演绎 <a class="header-anchor" href="#○-演绎" aria-label="Permalink to &quot;○ 演绎&quot;">​</a></h3><p>根据“大前提 -&gt; 小前提 -&gt; 结论”进行推理论证</p><h3 id="○-prep" tabindex="-1">○ PREP <a class="header-anchor" href="#○-prep" aria-label="Permalink to &quot;○ PREP&quot;">​</a></h3><p>根据“观点 -&gt; 理由 -&gt; 案例 -&gt; 重申”进行即兴发言</p><h3 id="○-scqa" tabindex="-1">○ SCQA <a class="header-anchor" href="#○-scqa" aria-label="Permalink to &quot;○ SCQA&quot;">​</a></h3><p>根据“情境/背景 -&gt; 冲突/痛点 -&gt; 问题 -&gt; 答案/建议”进行汇报、说服</p><h3 id="○-star" tabindex="-1">○ STAR <a class="header-anchor" href="#○-star" aria-label="Permalink to &quot;○ STAR&quot;">​</a></h3><p>根据“情境 -&gt; 任务 -&gt; 行动 -&gt; 结果”来描述个人贡献、复盘项目</p><h3 id="○-fabe" tabindex="-1">○ FABE <a class="header-anchor" href="#○-fabe" aria-label="Permalink to &quot;○ FABE&quot;">​</a></h3><p>根据“特点 -&gt; 优势 -&gt; 利益 -&gt; 证据”来推销</p><h3 id="○-ride" tabindex="-1">○ RIDE <a class="header-anchor" href="#○-ride" aria-label="Permalink to &quot;○ RIDE&quot;">​</a></h3><p>根据“风险 -&gt; 利益 1 -&gt; 缺点 -&gt; 利益 2”来谈判博弈说服</p><h3 id="○-aida" tabindex="-1">○ AIDA <a class="header-anchor" href="#○-aida" aria-label="Permalink to &quot;○ AIDA&quot;">​</a></h3><p>根据“注意 -&gt; 兴趣 -&gt; 欲望 -&gt; 行动”来激发行动</p><h3 id="○-电梯演讲" tabindex="-1">○ 电梯演讲 <a class="header-anchor" href="#○-电梯演讲" aria-label="Permalink to &quot;○ 电梯演讲&quot;">​</a></h3><p>根据“共情 -&gt; 问题 -&gt; 方案 -&gt; 价值”来吸引投资</p>',51)])])}const b=e(o,[["render",i]]);export{u as __pageData,b as default};
